sql:
SELECT c.customer_name, o.order_date
FROM customers c
INNER JOIN orders o ON c.customer_id = o.customer_id;

external_knowledge:
- 'blossoms' metaphorically refers to orders;
- 'completed their journey through the orchard' means the status of the orders is 'completed';
- 'petals we can now pluck to admire' metaphorically refers to the order IDs and customer names being retrieved.

- 'folks' refers to the customers; 
- 'haven't received their shipments' means the shipment_id is NULL, indicating the order hasn't been shipped;
- 'order details' includes the order ID, invoice number, and total amount of the order;
- 'when they ordered' refers to the order date.

- "star of the inventory" is a metaphor for a product;
- "shone the brightest" indicates the product with the highest attention or popularity;
- "attracting the largest crowd of admirers" refers to the product having the highest total quantity ordered;
- "as measured by the sum of its orders" is an explanation of how the product's popularity is quantified.

sql:
SELECT SUM(oi.price * oi.quantity) / COUNT(DISTINCT o.order_id) AS average_order_value
FROM order_items oi
INNER JOIN orders o ON oi.order_id = o.order_id;

SELECT c.customer_name, c.email, c.country, c.address, c.date_of_birth
FROM customers c
WHERE c.customer_id IN (
    SELECT DISTINCT customer_id
    FROM payments
) AND c.customer_id IN (
    SELECT DISTINCT customer_id
    FROM customer_interactions
    WHERE interaction_type = 'view customer data'
);

SELECT permissions.permission_name, roles.role_name
FROM permissions
INNER JOIN roles ON permissions.role_id = roles.role_id;

SELECT AVG(
    strftime('%Y', 'now') - strftime('%Y', c.date_of_birth) 
    - (strftime('%m%d', 'now') < strftime('%m%d', c.date_of_birth))
) AS average_age
FROM customers c
JOIN orders o ON c.customer_id = o.customer_id;
